  "action": "write_attribute",
  "action_input": "{\"device_id\": \"living_room_air_conditioner_1\", \"endpoint_id\": 1, \"cluster_id\": \"FanControl\", \"attribute_id\": \"PercentSetting\", \"value\": 50}"
}

{
  "thought": "Now for the utility room dehumidifier, set fan speed to a non-zero value to meet the optional action.",
  "action": "write_attribute",
  "action_input": "{\"device_id\": \"utility_room_dehumidifier_1\", \"endpoint_id\": 1, \"cluster_id\": \"FanControl\", \"attribute_id\": \"PercentSetting\", \"value\": 50}"
}

{
